53	const DEFAULT_MARKER = "<!-- code-review -->";
54	const MAX_SUGGESTION_LINES = 10;
55	
56	/** Count lines in a suggestion string (empty suggestion "" = 1 line — delete range). */
57	const countSuggestionLines = (text: string): number => text.split("\n").length;
58	
59	/** Extract and check suggestion blocks in a comment body, stripping those that are too long. */
60	const checkLongSuggestions = (
61	  comments: readonly InlineComment[],
62	): { readonly comments: readonly InlineComment[]; readonly longFiles: readonly string[] } => {
63	  const longFiles: string[] = [];
64	  const adjusted = comments.map((c) => {
65	    const match = /```suggestion\n([\s\S]*?)\n```/.exec(c.body);
66	    if (match?.[1] && countSuggestionLines(match[1]) > MAX_SUGGESTION_LINES) {
67	      longFiles.push(`${c.path}:${String(c.line)}`);
68	      return {
69	        ...c,
70	        body: c.body.replace(
71	          /```suggestion\n[\s\S]*?\n```/,
72	          "*(suggestion omitted — exceeds GitHub's ~10-line suggestion limit; see summary)*",
73	        ),
74	      };
75	    }
76	    return c;
77	  });
78	  return { comments: adjusted, longFiles };
79	};
